import type { ImageSourcePropType } from "react-native";

/**
 * Canvas sticker tool catalog (mobile copy of the shared
 * `@one-colored-pixel/coloring-ui` CANVAS_STICKERS) + the bundled-PNG
 * registry. The 36 transparent stickers a kid stamps onto the canvas — flat
 * vector art generated by `apps/chunky-crayon-web/scripts/
 * generate-canvas-stickers.ts`, copied into `assets/stickers/canvas/`.
 *
 * Mobile keeps a LOCAL copy (ids must stay byte-identical to the package's
 * catalog) rather than importing the web-oriented coloring-ui package into the
 * RN bundle — the same duplicate-catalog pattern as lib/colo/catalog.ts and
 * lib/avatars.ts. `STICKER_IMAGES` resolves a sticker id → bundled PNG via a
 * static require() map (Metro needs static paths). Every sticker is an
 * illustrated PNG; there is no emoji fallback.
 */

export type CanvasStickerCategory =
  | "stars"
  | "hearts"
  | "shapes"
  | "nature"
  | "animals"
  | "fun";

export type CanvasSticker = {
  id: string;
  name: string;
  category: CanvasStickerCategory;
};

