export const CANVAS_STICKER_CATEGORIES: {
  category: CanvasStickerCategory;
  name: string;
}[] = [
  { category: "stars", name: "Stars" },
  { category: "hearts", name: "Hearts" },
  { category: "shapes", name: "Shapes" },
  { category: "nature", name: "Nature" },
  { category: "animals", name: "Animals" },
  { category: "fun", name: "Fun" },
];

export const getCanvasSticker = (id: string): CanvasSticker | undefined =>
  CANVAS_STICKERS.find((s) => s.id === id);

export const getCanvasStickersByCategory = (
  category: CanvasStickerCategory,
): CanvasSticker[] => CANVAS_STICKERS.filter((s) => s.category === category);

